const body = $input.first().json.body;
const headers = $input.first().json.headers || {};

// Admin auth check
const adminToken = headers['x-admin-token'] || '';
if (adminToken !== 'b9cd461c9cd9a90ee16c3dd40f8637e3') {
  return [{ json: { error: 'Unauthorized', success: false } }];
}

const email = (body.email || '').trim().toLowerCase();
const plan = body.plan || 'basic';
const projectType = body.projectType || 'cosmetic';

if (!email) {
  return [{ json: { error: 'Email is required', success: false } }];
}

// Generate unique auth token for the new user
const chars = 'abcdef0123456789';
let token = '';
for (let i = 0; i < 32; i++) {
  token += chars[Math.floor(Math.random() * chars.length)];
}

return [{ json: {
  email,
  plan,
  projectType,
  authToken: token,
  valid: true
}}];

const regData = $('Validate & Generate Token').first().json;
const spreadsheet = $input.first().json;
const spreadsheetId = spreadsheet.spreadsheetId;

// Build header rows based on project type
let headerRequests = [];

if (regData.projectType === 'project') {
  headerRequests = [
    {
      range: 'Tasks!A1:K1',
      values: [['TaskID', 'ProjectName', 'TaskName', 'Description', 'Status', 'Priority', 'DueDate', 'AssignedTo', 'CreatedAt', 'UpdatedAt', 'Notes']]
    },
    {
      range: 'Projects!A1:E1',
      values: [['ProjectID', 'ProjectName', 'Description', 'Status', 'CreatedAt']]
    }
  ];
} else {
  headerRequests = [
    {
      range: 'Formulas!A1:J1',
      values: [['FormulaID', 'Name', 'Category', 'Description', 'TargetPH', 'TotalPct', 'Status', 'CreatedAt', 'UpdatedAt', 'Notes']]
    },
    {
      range: 'Ingredients!A1:I1',
      values: [['IngredientID', 'FormulaID', 'IngredientName', 'INCIName', 'Percentage', 'Phase', 'Function', 'MaxPct', 'SupplierNotes']]
    },
    {
      range: 'FormulaVersions!A1:G1',
      values: [['VersionID', 'FormulaID', 'VersionNumber', 'ChangeDescription', 'ChangedBy', 'CreatedAt', 'Snapshot']]
    }
  ];
}

return [{ json: {
  spreadsheetId,
  headerRequests,
  email: regData.email,
  authToken: regData.authToken,
  plan: regData.plan,
  projectType: regData.projectType
}}];
